import React, { useState } from 'react';
import { Link } from 'react-router-dom';
import { Ethereum, Celo } from 'lucide-react';

const NavigationBar = () => {
  const [iconState, setIconState] = useState('ethereum');

  const toggleIcon = () => {
    setIconState(prevState => prevState === 'ethereum' ? 'celo' : 'ethereum');
  };

  return (
    <nav className="w-full h-16 bg-black flex items-center justify-between px-6 text-white font-['Chakra Petch']">
      <div className="flex items-center space-x-8">
        <Link to="/" className="text-xl font-semibold">
          LookIntoMaxi
        </Link>
        <div className="flex space-x-6 text-sm">
          <Link to="https://lookintomaxi.com/">Δ Discounts</Link>
          <Link to="https://lookintomaxi.com/">% Discounts</Link>
          <Link to="https://lookintomaxi.com/">Arbs</Link>
          <Link to="https://lookintomaxi.com/">Apy</Link>
          <Link to="https://lookintomaxi.com/">Leagues</Link>
          <Link to="https://lookintomaxi.com/">Gas</Link>
        </div>
      </div>
      <div className="flex items-center space-x-4">
        <button
          onClick={toggleIcon}
          className="w-10 h-10 bg-white rounded-lg flex items-center justify-center"
        >
          {iconState === 'ethereum' ? (
            <Ethereum className="text-black" size={24} />
          ) : (
            <Celo className="text-black" size={24} />
          )}
        </button>
        <Link
          to="https://lookintomaxi.com/"
          className="px-6 py-2 border border-white rounded-md text-sm"
        >
          Buy
        </Link>
      </div>
    </nav>
  );
};

export default NavigationBar;
